    private void loadState(){
        SharedPreferences p=prefs(), old=getSharedPreferences(OLD_REMOTE_PREFS,Context.MODE_PRIVATE);
        String u=p.getString(KEY_URL,""); if(u.isEmpty()) u=old.getString("comfyui_url",""); urlInput.setText(u);
        String id=p.getString(KEY_CF_ID,""); if(id.isEmpty()) id=old.getString("cf_access_client_id",""); cfIdInput.setText(id);
        String sec=p.getString(KEY_CF_SECRET,""); if(sec.isEmpty()) sec=old.getString("cf_access_client_secret",""); cfSecretInput.setText(sec);
        if(!safe(u).trim().isEmpty()) topPanel.setVisibility(View.GONE); lastOutput=p.getString(KEY_OUTPUT,"");
        try{workflow=new JSONObject(p.getString(KEY_WORKFLOW,"{}")); if(workflow.length()==0) workflow=null;}catch(Exception e){workflow=null;} try{options=new JSONObject(p.getString(KEY_OPTIONS,"{}"));}catch(Exception e){options=new JSONObject();}
        loadTemplateCache();
    }

    private void saveConn(){ prefs().edit().putString(KEY_URL,rawUrl()).putString(KEY_CF_ID,cfIdInput.getText().toString().trim()).putString(KEY_CF_SECRET,cfSecretInput.getText().toString().trim()).apply(); try{CookieManager.getInstance().flush();}catch(Exception ignored){} }

